import json
from datetime import datetime, timezone

components = {
    'nexus-download': {
        'status': r'''{{inputs.parameters.nexus-status}}''',
        'downloadSpeedBytesPerSecond': float(r'''{{inputs.parameters.nexus-download-speed}}''')
    },
    'bitbucket-network': {
        'status': r'''{{inputs.parameters.bitbucket-status}}''',
        'totalSeconds': float(r'''{{inputs.parameters.bitbucket-total-seconds}}''')
    },
    'buildkit-network': {
        'status': r'''{{inputs.parameters.buildkit-status}}''',
        'totalSeconds': float(r'''{{inputs.parameters.buildkit-total-seconds}}''')
    },
    'harbor-registry-network': {
        'status': r'''{{inputs.parameters.registry-status}}''',
        'totalSeconds': float(r'''{{inputs.parameters.registry-total-seconds}}''')
    },
    'container-io': {
        'status': r'''{{inputs.parameters.container-io-status}}''',
        'writeBytesPerSecond': float(r'''{{inputs.parameters.container-write-speed}}'''),
        'readBytesPerSecond': float(r'''{{inputs.parameters.container-read-speed}}''')
    }
}

slow_components = [
    name for name, metrics in components.items()
    if metrics['status'] == 'SLOW'
]
bottleneck_status = 'SLOW' if slow_components else 'OK'
report = {
    'timestamp': datetime.now(timezone.utc).isoformat(),
    'bottleneckStatus': bottleneck_status,
    'slowComponents': slow_components,
    'components': components
}

open('/tmp/bottleneck-report.json', 'w', encoding='utf-8').write(
    json.dumps(report, ensure_ascii=False, separators=(',', ':'))
)
open('/tmp/bottleneck-status.txt', 'w', encoding='utf-8').write(bottleneck_status)
open('/tmp/slow-components.txt', 'w', encoding='utf-8').write(','.join(slow_components))
print(json.dumps(report, ensure_ascii=False))
